noteContentFormat:
{% set question = selector:.QuestionHeader-title|first ?? title|replace:" - 知乎":"" %}
{% set answer_author = selector:.AnswerItem[itemprop="mainEntityOfPage"] .AuthorInfo .UserLink-link|last ?? schema:author.name ?? author %}
{% set author_url = selector:.AnswerItem[itemprop="mainEntityOfPage"] .AuthorInfo .UserLink-link?href|last %}
{% set published_meta = selector:.AnswerItem[itemprop="mainEntityOfPage"] meta[itemprop="dateCreated"]?content %}
{% set modified_meta = selector:.AnswerItem[itemprop="mainEntityOfPage"] meta[itemprop="dateModified"]?content ?? published_meta %}
{% set published_text = selector:.AnswerItem[itemprop="mainEntityOfPage"] .ContentItem-time a?aria-label|first ?? selector:.AnswerItem[itemprop="mainEntityOfPage"] .ContentItem-time a?data-tooltip|first ?? published_meta %}
{% set modified_text = selector:.AnswerItem[itemprop="mainEntityOfPage"] .ContentItem-time a|first ?? modified_meta %}
{% set upvotes = selector:.AnswerItem[itemprop="mainEntityOfPage"] [itemprop="upvoteCount"]?content %}
{% set comments = selector:.AnswerItem[itemprop="mainEntityOfPage"] meta[itemprop="commentCount"]?content %}
{% set answer_html = selectorHtml:.AnswerItem[itemprop="mainEntityOfPage"] .RichContent-inner|replace_tags:"a":"span"|remove_html:"svg"|replace:"/<p[^>]*>\s*<span class=\"ztext-math\"[^>]*data-tex=\"([^\"]*?)\"[^>]*>(?:(?!<\\/p>)[\\s\\S])*?<\\/span><\\/span><\\/span>\s*<span class=\"ztext-math\"[^>]*data-tex=\"([^\"]*?)\"[^>]*>(?:(?!<\\/p>)[\\s\\S])*?<\\/span><\\/span><\\/span>\s*<\\/p>/g":"\n\n@@DISPLAY@@$1@@ENDDISPLAY@@\n\n@@DISPLAY@@$2@@ENDDISPLAY@@\n\n"|replace:"/<p[^>]*>\s*<span class=\"ztext-math\"[^>]*data-tex=\"([^\"]*?)\"[^>]*>(?:(?!<\\/p>)[\\s\\S])*?<\\/span><\\/span><\\/span>\s*<\\/p>/g":"\n\n@@DISPLAY@@$1@@ENDDISPLAY@@\n\n"|replace:"/<span class=\"ztext-math\"[^>]*data-tex=\"([^\"]*?)\"[^>]*>[\\s\\S]*?<\\/span><\\/span><\\/span>/g":"@@INLINE@@$1@@ENDINLINE@@"|remove_tags:"span" %}
{% set answer_markdown = answer_html|markdown|replace:"/@@DISPLAY@@([\\s\\S]*?)@@ENDDISPLAY@@/g":"\n\n$$$$\n$1\n$$$$\n\n"|replace:"/@@INLINE@@([\\s\\S]*?)@@ENDINLINE@@/g":"$$$1$$"|replace:"&amp;":"&" %}
# {{question}}

> [!info] 知乎回答
> 作者: {% if author_url %}[{{answer_author}}](https:{{author_url}}){% else %}{{answer_author}}{% endif %}
> 原文: [{{url}}]({{url}})
> 发布时间: {{published_text|replace:"发布于 ":""|replace:"T":" "|replace:".000Z":" UTC"}}
{% if modified_text and modified_text != published_text %}> 更新时间: {{modified_text|replace:"编辑于 ":""|replace:"发布于 ":""|replace:"T":" "|replace:".000Z":" UTC"}}
{% endif %}{% if upvotes or comments %}> 赞同: {{upvotes ?? "0"}} | 评论: {{comments ?? "0"}}
{% endif %}
## 回答正文

{{answer_markdown}}

{% if highlights %}
## 高亮

{{highlights|fragment_link:"回到原文"|join:"\n\n"}}
{% endif %}
